var maxSumRangeQuery = function(nums, requests) {
    const MOD = 1000000007n;
    const n = nums.length;
    const diff = new Array(n + 1).fill(0);
    for (const [start, end] of requests) {
        diff[start] += 1;
        diff[end + 1] -= 1;
    }
    const count = new Array(n).fill(0);
    let running = 0;
    for (let i = 0; i < n; i++) {
        running += diff[i];
        count[i] = running;
    }
    count.sort((a, b) => a - b);
    const numsSorted = [...nums].sort((a, b) => a - b);
    let total = 0n;
    for (let i = 0; i < n; i++) {
        total = (total + BigInt(count[i]) * BigInt(numsSorted[i])) % MOD;
    }
    return Number(total);
};
